local jwt = require('resty.jwt') -- assuming you have jwt module installed and configured in your openresty installation

-- function to verify JWT token
function validate_token(token)
  local hs256 = 'your_secret'   -- replace with actual secret key
  local success, err_msg = jwt.verify(hs256, token)
  if not success then
    ngx.log(ngx.WARN, "JWT validation error: ", err_msg)
    return nil, err_msg
  end
  
  local payload = jwt.decode(token)
  if not payload or not payload["role"] then
    ngx.log(ngx.ERR, "Invalid JWT token - missing role claim")
    return nil, "Invalid JWT Token"
  end
  
  -- assuming admin and user roles are supported
  local user_role = payload["role"]
  if not (user_role == 'admin' or user_role == 'user') then
    ngx.log(ngx.ERR, "Invalid role: ", user_role)
    return nil, "Invalid Role"
  end
  
  -- Set the role as variable for other scripts to use if need be
  ngx.var.jwt_user_role = user_role

  return true
end

-- Check if request uri contains certain strings
local uri = ngx.var.uri
if not (string.match(uri, "/admin") or string.match(uri, "/api")) then
  -- Get the token from headers and validate it
  local auth_header = ngx.req.get_headers()["authorization"]
  
  if not auth_header or not auth_header:sub(1,7) == 'Bearer ' then
    ngx.log(ngx.WARN, "Missing/Invalid Authorization header")
    return ngx.HTTP_UNAUTHORIZED   -- send HTTP status code 401 - unauthorized access
  end

  local token = auth_header:sub(8)  -- get the actual JWT from Bearer Token scheme
